mapper.select:
select 
from student


        and student_name like concat('%', #{studentName}, '%')


        and student_phone like concat('%', #{studentPhone}, '%')


        and education = #{education}


        and school like concat('%', #{school}, '%')


        and teaching_mode = #{teachingMode}


        and student_tag = #{studentTag}


        and status = #{status}


order by id desc
